const raw = $json.content.parts[0].text;

const cleaned = raw
  .replace(/^```json\s*/i, '')
  .replace(/^```\s*/i, '')
  .replace(/\s*```$/i, '');

const data = JSON.parse(cleaned);

const score = Math.max(0, 100 - (data.mistakes.length * 2));

let rows = "";

for (const m of data.mistakes) {
  rows += `
    <tr>
      <td style="color:#dc2626;font-weight:bold;">
        ${m.wrong} ❌
      </td>
      <td style="color:#16a34a;font-weight:bold;">
        ${m.correct}
      </td>
      <td>
        ${m.explanation}
      </td>
    </tr>
  `;
}

const emailHtml = `
<!DOCTYPE html>
<html>
<head>
<meta charset="UTF-8">
<style>

body{
    font-family: Arial, sans-serif;
    margin:40px;
    color:#333;
    line-height:1.6;
}

.report-header{
    text-align:center;
    margin-bottom:40px;
}

.report-header h1{
    color:#1a365d;
}

.score-box{
    background:#f8fafc;
    border:1px solid #dbeafe;
    border-radius:8px;
    padding:20px;
    margin-bottom:30px;
}

.score{
    font-size:24px;
    font-weight:bold;
    color:#1a365d;
}

table{
    width:100%;
    border-collapse:collapse;
}

th{
    background:#f2f2f2;
}

th,td{
    border:1px solid #ddd;
    padding:12px;
    text-align:left;
}

</style>
</head>
<body>

<div class="report-header">
    <h1>AI Document Correction Report</h1>
</div>

<div class="score-box">
    <div class="score">
        Document Score: ${score}/100
    </div>

    <div>
        Total Mistakes Found: ${data.mistakes.length}
    </div>
</div>

<table>

<tr>
    <th>❌ Incorrect</th>
    <th>✅ Correct</th>
    <th>Explanation</th>
</tr>

${rows}

</table>

<p style="margin-top:30px;">
The corrected document is attached as a PDF.
</p>

</body>
</html>
`;

return [{
  json: {
    emailHtml,
    correctedDocumentHtml: data.corrected_document_html,
    score,
    totalMistakes: data.mistakes.length
  }
}];

return [{
